t.script:

document.addEventListener('DOMContentLoaded', function () {
    var pageSize = 8;
    var currentPage = 1;
    var searchInput = document.querySelector('.prq-job-search');
    var searchBtn = document.querySelector('.prq-search-btn');
    var jobCards = Array.prototype.slice.call(document.querySelectorAll('.prq-job-card'));
    var noResults = document.querySelector('.prq-no-results');
    var toolbar = document.querySelector('.prq-jobs-toolbar');
    var resultCount = document.querySelector('.prq-jobs-result-count');
    var pageButtons = document.querySelector('.prq-page-buttons');
    var loadMore = document.querySelector('.prq-load-more');

    if ('IntersectionObserver' in window) {
        var observer = new IntersectionObserver(function (entries) {
            entries.forEach(function (entry) {
                if (entry.isIntersecting) {
                    entry.target.classList.add('animate-loaded');
                }
            });
        }, {
            threshold: 0.1,
            rootMargin: '0px 0px -100px 0px'
        });

        document.querySelectorAll(
            '.careers-hero, .why-section, .openings-section, .process-section, .life-section, .cta-section'
        ).forEach(function (section) {
            observer.observe(section);
        });
    }

    function getJobSearchText(card) {
        return String(
            card.getAttribute('data-search') ||
            card.textContent ||
            ''
        ).toLowerCase();
    }

    function getFilteredCards() {
        var query = searchInput ? String(searchInput.value || '').toLowerCase().trim() : '';

        if (!query) {
            return jobCards;
        }

        return jobCards.filter(function (card) {
            return getJobSearchText(card).indexOf(query) !== -1;
        });
    }

    function renderPageButtons(totalPages) {
        if (!pageButtons) {
            return;
        }

        pageButtons.innerHTML = '';

        for (var page = 1; page <= totalPages; page += 1) {
            var button = document.createElement('button');
            button.type = 'button';
            button.className = 'jobs-page-btn' + (page === currentPage ? ' active' : '');
            button.textContent = page;
            button.setAttribute('data-page', String(page));
            pageButtons.appendChild(button);
        }
    }

    function renderJobs() {
        if (!jobCards.length) {
            if (noResults) {
                noResults.classList.add('prq-hidden');
            }
            if (toolbar) {
                toolbar.classList.add('prq-hidden');
            }
            return;
        }

        var filteredCards = getFilteredCards();
        var total = filteredCards.length;
        var totalPages = Math.max(1, Math.ceil(total / pageSize));

        if (currentPage > totalPages) {
            currentPage = totalPages;
        }

        var startIndex = (currentPage - 1) * pageSize;
        var endIndex = startIndex + pageSize;

        jobCards.forEach(function (card) {
            card.classList.add('prq-hidden');
        });

        filteredCards.slice(startIndex, endIndex).forEach(function (card, index) {
            card.classList.remove('prq-hidden');
            card.style.animationDelay = String(index * 0.08) + 's';
        });

        if (noResults) {
            noResults.classList.toggle('prq-hidden', total !== 0);
        }

        if (toolbar) {
            toolbar.classList.toggle('prq-hidden', total <= pageSize && currentPage === 1);
        }

        if (resultCount) {
            if (total) {
                resultCount.textContent = 'Showing ' + (startIndex + 1) + '-' + Math.min(endIndex, total) + ' of ' + total + ' job(s)';
            } else {
                resultCount.textContent = 'No jobs found';
            }
        }

        renderPageButtons(totalPages);

        if (loadMore) {
            loadMore.disabled = currentPage >= totalPages;
            loadMore.classList.toggle('prq-hidden', total <= pageSize);
        }
    }

    function resetToFirstPage() {
        currentPage = 1;
        renderJobs();
    }

    if (searchInput) {
        searchInput.addEventListener('input', resetToFirstPage);
    }

    if (searchBtn) {
        searchBtn.addEventListener('click', resetToFirstPage);
    }

    if (pageButtons) {
        pageButtons.addEventListener('click', function (event) {
            var button = event.target.closest('[data-page]');

            if (!button) {
                return;
            }

            currentPage = parseInt(button.getAttribute('data-page'), 10) || 1;
            renderJobs();
        });
    }

    if (loadMore) {
        loadMore.addEventListener('click', function () {
            currentPage += 1;
            renderJobs();
        });
    }

    document.querySelectorAll('.stat-card, .benefit-card, .job-card, .life-card, .step').forEach(function (card) {
        card.addEventListener('mouseenter', function () {
            this.style.transform = 'translateY(-15px) scale(1.02)';
        });
        card.addEventListener('mouseleave', function () {
            this.style.transform = 'translateY(0) scale(1)';
        });
    });

    window.addEventListener('scroll', function () {
        var hero = document.querySelector('.careers-hero');
        if (hero) {
            hero.style.transform = 'translateY(' + (window.pageYOffset * 0.4) + 'px)';
        }
    });

    renderJobs();
});


document.addEventListener('DOMContentLoaded', function () {
    var isSubmitting = false;

    // =========================================================
    // Helpers
    // =========================================================
    function showFormError(message) {
        var popup = document.getElementById('errorPopup');
        var messageBox = document.getElementById('errorMessage');

        if (popup && messageBox) {
            messageBox.textContent = message;
            popup.style.display = 'block';

            try {
                popup.scrollIntoView({
                    behavior: 'smooth',
                    block: 'center'
                });
            } catch (err) {
                window.scrollTo(0, 0);
            }
        } else {
            alert(message);
        }
    }

    function clearSuggestions(suggestionsList) {
        if (suggestionsList) {
            suggestionsList.innerHTML = '';
            suggestionsList.style.display = 'none';
        }
    }

    function resetSubmitButton(submitBtn) {
        isSubmitting = false;

        if (submitBtn) {
            submitBtn.disabled = false;
            submitBtn.innerHTML = '<i class="fa fa-rocket"></i> Submit Application';
            submitBtn.style.pointerEvents = 'auto';
            submitBtn.style.opacity = '1';
        }
    }

    function getFieldValue(form, fieldName) {
        var field = form.querySelector('[name="' + fieldName + '"]');
        return field ? String(field.value || '').trim() : '';
    }

    function focusField(form, fieldName) {
        var field = form.querySelector('[name="' + fieldName + '"]');
        if (field && typeof field.focus === 'function') {
            field.focus();
        }
    }

    function validateRegex(form, fieldName, pattern, message) {
        var value = getFieldValue(form, fieldName);

        if (!pattern.test(value)) {
            showFormError(message);
            focusField(form, fieldName);
            return false;
        }

        return true;
    }

    function validateNumberRange(form, fieldName, minValue, maxValue) {
        var value = getFieldValue(form, fieldName);
        var label = fieldName.replace(/_/g, ' ');

        if (!/^[0-9]+$/.test(value)) {
            showFormError('Please enter a valid numeric value for ' + label + '.');
            focusField(form, fieldName);
            return false;
        }

        var numberValue = parseInt(value, 10);

        if (numberValue < minValue || numberValue > maxValue) {
            showFormError(
                label.replace(/\b\w/g, function (c) {
                    return c.toUpperCase();
                }) + ' must be between ' + minValue + ' and ' + maxValue + '.'
            );
            focusField(form, fieldName);
            return false;
        }

        return true;
    }

    function validateYesNo(form, fieldName, message) {
        var value = getFieldValue(form, fieldName);

        if (value !== 'yes' && value !== 'no') {
            showFormError(message);
            focusField(form, fieldName);
            return false;
        }

        return true;
    }

    function validateRequiredSelect(form, fieldName, message) {
        if (!getFieldValue(form, fieldName)) {
            showFormError(message);
            focusField(form, fieldName);
            return false;
        }

        return true;
    }

    function validateApplicationForm(form) {
        // Same validation logic as backend
        var validators = [
            {
                field: 'partner_name',
                pattern: /^[A-Za-z][A-Za-z\s'.-]{1,79}$/,
                message: 'Please enter a valid full name.'
            },
            {
                field: 'email_from',
                pattern: /^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$/,
                message: 'Please enter a valid email address.'
            },
            {
                field: 'partner_phone',
                pattern: /^\+?[0-9][0-9\s().-]{7,19}$/,
                message: 'Please enter a valid phone number.'
            },
            {
                field: 'partner_location',
                pattern: /^[A-Za-z0-9][A-Za-z0-9,\s'.-]{1,99}$/,
                message: 'Please enter a valid location.'
            },
            {
                field: 'linkedin_profile',
                pattern: /^(https?:\/\/)?([a-z]{2,3}\.)?linkedin\.com\/.*$/i,
                message: 'Please enter a valid LinkedIn URL.'
            }
        ];

        for (var i = 0; i < validators.length; i++) {
            var validator = validators[i];

            if (!validateRegex(
                form,
                validator.field,
                validator.pattern,
                validator.message
            )) {
                return false;
            }
        }

        if (!validateNumberRange(form, 'experience', 0, 60)) {
            return false;
        }

        if (!validateRequiredSelect(
            form,
            'nationality_id',
            'Please select a valid nationality.'
        )) {
            return false;
        }

        if (!validateNumberRange(form, 'salary_expected', 1, 100000000)) {
            return false;
        }

        if (!validateNumberRange(form, 'notice_period', 0, 3650)) {
            return false;
        }

        if (!validateYesNo(
            form,
            'will_relocate',
            'Please select a valid answer for relocation.'
        )) {
            return false;
        }

        if (!validateYesNo(
            form,
            'legally_required',
            'Please select a valid legal authorization option.'
        )) {
            return false;
        }

        return true;
    }

    function createSuggestionButton(value) {
        var button = document.createElement('button');

        button.type = 'button';
        button.className = 'suggestion-item';
        button.dataset.value = value;
        button.textContent = value;

        return button;
    }

    function renderSuggestionMessage(suggestionsList, message) {
        suggestionsList.innerHTML = '';

        var div = document.createElement('div');
        div.style.padding = '15px 20px';
        div.style.color = 'rgba(255,255,255,0.6)';
        div.style.textAlign = 'center';
        div.style.fontStyle = 'italic';
        div.textContent = message;

        suggestionsList.appendChild(div);
        suggestionsList.style.display = 'block';
    }

    // =========================================================
    // Scroll animations
    // =========================================================
    if ('IntersectionObserver' in window) {
        var observerOptions = {
            threshold: 0.1,
            rootMargin: '0px 0px -100px 0px'
        };

        var observer = new IntersectionObserver(function (entries) {
            entries.forEach(function (entry) {
                if (entry.isIntersecting) {
                    entry.target.classList.add('animate-loaded');
                }
            });
        }, observerOptions);

        document.querySelectorAll(
            '.job-detail-hero, .job-card-detail, .job-description-section, .apply-card'
        ).forEach(function (el) {
            observer.observe(el);
        });
    }

    // =========================================================
    // Error popup close
    // =========================================================
    var errorClose = document.getElementById('errorClose');

    if (errorClose) {
        errorClose.addEventListener('click', function () {
            var popup = document.getElementById('errorPopup');

            if (popup) {
                popup.style.display = 'none';
            }
        });
    }

    // =========================================================
    // Skills tag picker
    // =========================================================
    (function initSkillPicker() {
        var picker = document.getElementById('skillPicker');
        var tagsContainer = document.getElementById('selectedSkillTags');
        var searchInput = document.getElementById('skillSearch');
        var optionsContainer = document.getElementById('skillOptions');
        var hiddenInputs = document.getElementById('selectedSkillInputs');

        if (!picker || !tagsContainer || !searchInput || !optionsContainer || !hiddenInputs) {
            return;
        }

        var options = Array.prototype.slice.call(optionsContainer.querySelectorAll('.skill-option'));
        var selectedSkills = {};
        var selectedOrder = [];

        function openPicker() {
            picker.classList.add('open');
            refreshOptions();
        }

        function closePicker() {
            picker.classList.remove('open');
        }

        function refreshOptions() {
            var query = String(searchInput.value || '').toLowerCase().trim();

            options.forEach(function (option) {
                var skillId = option.getAttribute('data-skill-id');
                var skillName = String(option.getAttribute('data-skill-name') || '');
                var skillType = String(option.getAttribute('data-skill-type') || '');
                var haystack = (skillName + ' ' + skillType).toLowerCase();
                var isSelected = Boolean(selectedSkills[skillId]);
                var isMatch = !query || haystack.indexOf(query) !== -1;

                option.classList.toggle('is-selected', isSelected);
                option.classList.toggle('is-hidden', !isMatch);
            });
        }

        function renderSelectedSkills() {
            tagsContainer.querySelectorAll('.skill-tag').forEach(function (tag) {
                tag.remove();
            });
            hiddenInputs.innerHTML = '';

            selectedOrder.forEach(function (skillId) {
                var skill = selectedSkills[skillId];

                if (!skill) {
                    return;
                }

                var tag = document.createElement('span');
                tag.className = 'skill-tag';
                tag.textContent = skill.name;

                var removeButton = document.createElement('button');
                removeButton.type = 'button';
                removeButton.setAttribute('aria-label', 'Remove ' + skill.name);
                removeButton.setAttribute('data-remove-skill', skillId);
                removeButton.innerHTML = '&times;';

                tag.appendChild(removeButton);
                tagsContainer.insertBefore(tag, searchInput);

                var hiddenInput = document.createElement('input');
                hiddenInput.type = 'hidden';
                hiddenInput.name = 'skill_ids';
                hiddenInput.value = skillId;
                hiddenInputs.appendChild(hiddenInput);
            });

            refreshOptions();
        }

        function addSkill(option) {
            var skillId = option.getAttribute('data-skill-id');

            if (!skillId || selectedSkills[skillId]) {
                return;
            }

            selectedSkills[skillId] = {
                name: option.getAttribute('data-skill-name') || option.textContent.trim()
            };
            selectedOrder.push(skillId);
            searchInput.value = '';
            renderSelectedSkills();
            searchInput.focus();
        }

        function removeSkill(skillId) {
            delete selectedSkills[skillId];
            selectedOrder = selectedOrder.filter(function (id) {
                return id !== skillId;
            });
            renderSelectedSkills();
            searchInput.focus();
        }

        picker.addEventListener('click', function () {
            openPicker();
            searchInput.focus();
        });

        searchInput.addEventListener('focus', openPicker);
        searchInput.addEventListener('input', refreshOptions);
        searchInput.addEventListener('keydown', function (event) {
            if (event.key === 'Backspace' && !searchInput.value && selectedOrder.length) {
                removeSkill(selectedOrder[selectedOrder.length - 1]);
            }

            if (event.key === 'Escape') {
                closePicker();
            }
        });

        optionsContainer.addEventListener('click', function (event) {
            var option = event.target.closest('.skill-option');

            if (!option || option.classList.contains('is-selected')) {
                return;
            }

            event.preventDefault();
            addSkill(option);
        });

        tagsContainer.addEventListener('click', function (event) {
            var removeButton = event.target.closest('[data-remove-skill]');

            if (!removeButton) {
                return;
            }

            event.preventDefault();
            removeSkill(removeButton.getAttribute('data-remove-skill'));
        });

        document.addEventListener('click', function (event) {
            if (!picker.contains(event.target)) {
                closePicker();
            }
        });
    })();

    // =========================================================
    // Form submit validation
    // =========================================================
    var form = document.getElementById('jobApplicationForm');
    var submitBtn = document.getElementById('submitBtn');

    if (form && submitBtn) {
        form.addEventListener('submit', function (e) {
            if (isSubmitting) {
                e.preventDefault();
                return false;
            }

            if (!validateApplicationForm(form)) {
                e.preventDefault();
                resetSubmitButton(submitBtn);
                return false;
            }

            isSubmitting = true;

            submitBtn.disabled = true;
            submitBtn.innerHTML = '<i class="fa fa-spinner fa-spin"></i> Submitting...';
            submitBtn.style.pointerEvents = 'none';
            submitBtn.style.opacity = '0.7';
        });
    }

    // =========================================================
    // Location suggestions
    // =========================================================
    var locationInput = document.getElementById('locationInput');
    var suggestionsList = document.getElementById('locationSuggestions');

    if (locationInput && suggestionsList) {
        var timer = null;

        suggestionsList.addEventListener('click', function (ev) {
            var target = ev.target.closest('.suggestion-item');

            if (!target) {
                return;
            }

            locationInput.value = target.dataset.value || target.textContent.trim();
            clearSuggestions(suggestionsList);
            locationInput.focus();
        });

        locationInput.addEventListener('input', function () {
            var term = this.value.trim();

            clearTimeout(timer);

            if (term.length < 2) {
                clearSuggestions(suggestionsList);
                return;
            }

            renderSuggestionMessage(suggestionsList, 'Searching locations...');

            timer = setTimeout(function () {
                fetch('/jobs/location_suggest', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({
                        jsonrpc: '2.0',
                        method: 'call',
                        params: {
                            term: term
                        },
                        id: new Date().getTime()
                    })
                })
                .then(function (response) {
                    if (!response.ok) {
                        throw new Error('Network response was not ok');
                    }

                    return response.json();
                })
                .then(function (data) {
                    var suggestions = [];

                    if (data && Array.isArray(data.result)) {
                        suggestions = data.result;
                    } else if (data && data.result) {
                        suggestions = [data.result];
                    }

                    suggestionsList.innerHTML = '';

                    if (!suggestions.length) {
                        renderSuggestionMessage(suggestionsList, 'No locations found');
                        return;
                    }

                    suggestions.slice(0, 8).forEach(function (item) {
                        var value = String(item || '').trim();

                        if (value) {
                            suggestionsList.appendChild(createSuggestionButton(value));
                        }
                    });

                    suggestionsList.style.display = 'block';
                })
                .catch(function (error) {
                    console.error('Location suggestion error:', error);
                    renderSuggestionMessage(suggestionsList, 'Unable to fetch locations');
                });
            }, 400);
        });

        document.addEventListener('click', function (e) {
            if (!locationInput.contains(e.target) && !suggestionsList.contains(e.target)) {
                clearSuggestions(suggestionsList);
            }
        });

        locationInput.addEventListener('focus', function () {
            if (suggestionsList.innerHTML.trim()) {
                suggestionsList.style.display = 'block';
            }
        });
    }

    // =========================================================
    // Hero parallax
    // =========================================================
    window.addEventListener('scroll', function () {
        var scrolled = window.pageYOffset || document.documentElement.scrollTop;
        var hero = document.querySelector('.job-detail-hero');

        if (hero) {
            hero.style.transform = 'translateY(' + (scrolled * 0.3) + 'px)';
        }
    });

    // =========================================================
    // Hover effects
    // =========================================================
    document.querySelectorAll(
        '.info-card, .job-card-detail, .job-description-section'
    ).forEach(function (card) {
        card.addEventListener('mouseenter', function () {
            this.style.transform = 'translateY(-15px) scale(1.02)';
        });

        card.addEventListener('mouseleave', function () {
            this.style.transform = 'translateY(0) scale(1)';
        });
    });

    // =========================================================
    // Reset submit state on browser back / refresh cache
    // =========================================================
    window.addEventListener('pageshow', function () {
        resetSubmitButton(submitBtn);
    });
});

document.addEventListener('DOMContentLoaded', function () {
// Scroll-triggered animations
const observerOptions = {
threshold: 0.1,
rootMargin: '0px 0px -50px 0px'
};

const observer = new IntersectionObserver(function(entries) {
entries.forEach(entry => {
if (entry.isIntersecting) {
entry.target.classList.add('animate-loaded');
}
});
}, observerOptions);

observer.observe(document.querySelector('.prq-success-container'));

// Particle system
var particlesContainer = document.getElementById('prqParticles');
if (!particlesContainer) return;

function createParticles() {
var colors = ['#d89a2b', '#e5b55b', '#f8e8b0'];
for (var i = 0; i
<
25; i++) {
var p = document.createElement('div');
var color = colors[Math.floor(Math.random() * colors.length)];
p.className = 'prq-particle';
p.style.background = color;
p.style.left = (20 + Math.random() * 60) + '%';
p.style.top = (20 + Math.random() * 40) + '%';
p.style.setProperty('--dx', (-150 + Math.random() * 300) + 'px');
p.style.setProperty('--dy', (-150 + Math.random() * 300) + 'px');
p.style.animationDuration = (1.5 + Math.random() * 1) + 's';
particlesContainer.appendChild(p);

// Remove particle after animation
(function (particle) {
setTimeout(function () {
if (particle.parentNode) particle.remove();
}, 2500);
})(p);
}
}

// Initial burst + continuous particles
createParticles();
setInterval(createParticles, 3500);

// Smooth hover effects
document.querySelectorAll('.prq-success-card, .details, .primary-btn, .secondary-btn').forEach(el => {
el.addEventListener('mouseenter', function() {
this.style.transform = 'translateY(-8px) scale(1.02)';
});
el.addEventListener('mouseleave', function() {
this.style.transform = 'translateY(0) scale(1)';
});
});

// Floating animation for checkmark
const checkmark = document.querySelector('.checkmark');
if (checkmark) {
checkmark.classList.add('animate-float');
}
});
